<?php require_once 'db.php'; require_once 'mailer.php'; $u=require_login('student'); verify_csrf(); $bid=(int)($_GET['booking_id']??$_POST['booking_id']??0); $st=pdo()->prepare('SELECT b.*,t.table_code,u.email,u.name FROM bookings b JOIN library_tables t ON t.id=b.table_id JOIN users u ON u.id=b.student_id WHERE b.id=? AND b.student_id=?'); $st->execute([$bid,$u['id']]); $b=$st->fetch(); if(!$b) exit('Booking not found.'); $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $txn=trim($_POST['transaction_id']??''); if(!preg_match('/^[A-Za-z0-9._-]{6,120}$/',$txn)) $err='Enter a valid transaction ID.'; else try{ pdo()->prepare('INSERT INTO payments(booking_id,transaction_id,amount) VALUES(?,?,?)')->execute([$bid,$txn,$b['amount']]); [$sub,$body]=email_template('pending',['name'=>$u['name']]); send_library_mail($u['id'],$u['email'],$sub,$body); header('Location: pending.php'); exit; }catch(Throwable $e){ $err='Duplicate transaction ID or payment already submitted.'; }} $upi='upi://pay?pa='.rawurlencode(UPI_ID).'&pn='.rawurlencode(PAYEE_NAME).'&am='.$b['amount'].'&cu='.CURRENCY.'&tn='.rawurlencode('Library Table '.$b['table_code']); app_header('Payment'); ?>
<section class="card pay"><h1>Pay ₹<?=e($b['amount'])?></h1><p>Table <?=e($b['table_code'])?>, <?=e($b['duration_days'])?> days. Scan QR, pay, then submit Transaction ID.</p><img class="qr" src="https://api.qrserver.com/v1/create-qr-code/?size=240x240&data=<?=urlencode($upi)?>" alt="UPI QR"><p class="mono"><?=e($upi)?></p><p class="error"><?=e($err)?></p><form method="post"><?=csrf_field()?><input type="hidden" name="booking_id" value="<?=e($bid)?>"><input name="transaction_id" placeholder="UPI Transaction ID" required><button class="btn">Submit for Approval</button></form></section><?php app_footer(); ?>
